index 76234ccfdcff..e942980c4d9f 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -2257,6 +2257,58 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
       return BinaryOperator::CreateAnd(Op0, ConstantInt::get(Ty, ~(*AndC)));
   }

+  // C - ((C1 - X) & M) --> (C - (C1 & M)) + (X & M) when:
+  //   (1) C1 & ~M == ~M, or
+  //   (2) (C1 - ((C1 & M) - 1)) is a power of 2 and
+  //       ((C1 + M) & ((C1 & M) - 1)) == ((C1 & M) - 1) and the sub has nuw
+  // When C == (C1 & M), this simplifies to just (X & M).
+  const APInt *CVal, *C1Val, *MVal;
+  Value *XVal;
+  if (match(Op0, m_APInt(CVal)) &&
+      match(Op1, m_OneUse(m_And(m_Sub(m_APInt(C1Val), m_Value(XVal)),
+                                 m_APInt(MVal)))) &&
+      (*C1Val & ~(*MVal)) == ~(*MVal)) {
+    // Case 1: All low bits of C1 outside M are set. Works without nuw.
+    APInt AndMask = *MVal;
+    // If the inner sub has nuw, narrow the mask using known bits from C1.
+    if (cast<Instruction>(cast<Instruction>(Op1)->getOperand(0))
+            ->hasNoUnsignedWrap())
+      AndMask &= APInt::getLowBitsSet(Ty->getScalarSizeInBits(),
+                                      C1Val->getActiveBits());
+    APInt C1AndM = *C1Val & *MVal;
+    if (*CVal == C1AndM)
+      return BinaryOperator::CreateAnd(XVal, ConstantInt::get(Ty, AndMask));
+    Constant *AddC = ConstantInt::get(Ty, *CVal - C1AndM);
+    Value *And = Builder.CreateAnd(XVal, ConstantInt::get(Ty, AndMask));
+    return BinaryOperator::CreateAdd(And, AddC);
+  }
+
+  // Case 2: Check power-of-2 condition with nuw.
+  if (match(Op0, m_APInt(CVal)) &&
+      match(Op1, m_OneUse(m_And(m_Sub(m_APInt(C1Val), m_Value(XVal)),
+                                 m_APInt(MVal)))) &&
+      cast<Instruction>(cast<Instruction>(Op1)->getOperand(0))
+          ->hasNoUnsignedWrap()) {
+    APInt C1AndM = *C1Val & *MVal;
+    APInt Diff = *C1Val - (C1AndM - 1);
+    if (Diff.isPowerOf2()) {
+      APInt Sum = *C1Val + *MVal;
+      APInt Mask = C1AndM - 1;
+      if ((Sum & Mask) == Mask) {
+        APInt AndMask = *MVal;
+        // Narrow mask using known bits from C1 (X <= C1 due to nuw).
+        AndMask &= APInt::getLowBitsSet(Ty->getScalarSizeInBits(),
+                                        C1Val->getActiveBits());
+        if (*CVal == C1AndM)
+          return BinaryOperator::CreateAnd(XVal,
+                                           ConstantInt::get(Ty, AndMask));
+        Constant *AddC = ConstantInt::get(Ty, *CVal - C1AndM);
+        Value *And = Builder.CreateAnd(XVal, ConstantInt::get(Ty, AndMask));
+        return BinaryOperator::CreateAdd(And, AddC);
+      }
+    }
+  }
+
   if (Instruction *V =
           canonicalizeCondSignextOfHighBitExtractToSignextHighBitExtract(I))
     return V;

