  // sub(C1 & M, and(sub_nuw(C1, X), M)) --> and(X, M')
  // When the low bits of C1 (that are masked off by M) are all set,
  // the subtraction result simplifies to just X masked with M.
  // The mask M' is narrowed using known bits from C1 (X <= C1 due to nuw).
  const APInt *C2, *C1Val, *MVal;
