    APInt NarrowMask = *MVal & APInt::getLowBitsSet(Ty->getScalarSizeInBits(),
                                                    C1Val->getActiveBits());
    return BinaryOperator::CreateAnd(XVal, ConstantInt::get(Ty, NarrowMask));
  }
